  1→/**
  2→ * slog - structured logging module
  3→ */
  4→
  5→/**
  6→ * The type of a key/value pair to be logged.
  7→ */
  8→export type KVPair = [string, any];
  9→
 10→/**
 11→ * Structured Log class that uses log levels and KVPair's to log to the console.
 12→ */
 13→export class SLog {
 14→  /** Debug log level. */
 15→  readonly LevelDebug: number = -4;
 16→
 17→  /** Info log level. */
 18→  readonly LevelInfo: number = 0;
 19→
 20→  /** Warning log level. */
 21→  readonly LevelWarn: number = 4;
 22→
 23→  /** Error log level. */
 24→  readonly LevelError: number = 8;
 25→
 26→  /** Current log severity level. Should only be changed by setLevel. */
 27→  private level: number = this.LevelInfo;
 28→
 29→  /**
 30→   * Internal function to actually write to the log.
 31→   *
 32→   * @param level string name of level
 33→   * @param msg message to be printed
 34→   * @param pairs structured pairs to be logged
 35→   */
 36→  private log(level: string, msg: string, pairs: Array<KVPair>) {
 37→    console.log(`START ${level}: ${msg}`);
 38→    for (let pair of pairs) {
 39→      console.log(pair[0]);
 40→      console.log(pair[1]);
 41→    }
 42→    console.log(`END ${level}: ${msg}`);
 43→  }
 44→
 45→  /**
 46→   * Set the logging severity level to control what messages will appear in the
 47→   * logs.  Messages at or above this severity will be logged.
 48→   *
 49→   * @param level log severity level to use
 50→   */
 51→  setLevel(level: number): void {
 52→    this.level = level;
 53→  }
 54→
 55→  /**
 56→   * Log debug message.
 57→   *
 58→   * @param msg log message
 59→   * @param pairs key/value pairs to be logged
 60→   */
 61→  debug(msg: string, ...pairs: Array<KVPair>): void {
 62→    if (this.level <= this.LevelDebug) {
 63→      this.log("DEBUG", msg, pairs);
 64→    }
 65→  }
 66→
 67→  /**
 68→   * Log informational message.
 69→   *
 70→   * @param msg log message
 71→   * @param pairs key/value pairs to be logged
 72→   */
 73→  info(msg: string, ...pairs: Array<KVPair>): void {
 74→    if (this.level <= this.LevelInfo) {
 75→      this.log("INFO", msg, pairs);
 76→    }
 77→  }
 78→
 79→  /**
 80→   * Log warning message.
 81→   *
 82→   * @param msg log message
 83→   * @param pairs key/value pairs to be logged
 84→   */
 85→  warn(msg: string, ...pairs: Array<KVPair>): void {
 86→    if (this.level <= this.LevelWarn) {
 87→      this.log("WARNING", msg, pairs);
 88→    }
 89→  }
 90→
 91→  /**
 92→   * Log error message.
 93→   *
 94→   * @param msg log message
 95→   * @param pairs key/value pairs to be logged
 96→   */
 97→  error(msg: string, ...pairs: Array<KVPair>): void {
 98→    if (this.level <= this.LevelError) {
 99→      this.log("ERROR", msg, pairs);
100→    }
101→  }
102→}
103→
104→/** Single, constant, globally accessible structured log. */
105→export const slog: SLog = new SLog();
