 15→describe("Login/Logout Tests", () => {
 16→  beforeEach(() => {
 17→    cy.visit("/");
 18→  });
 19→
 20→  it("should login", () => {
 21→    // Intercept login request
 22→    cy.intercept(
 23→      "POST",
 24→      `${Cypress.env("DATABASE_HOST")}${Cypress.env("AUTH_PATH")}`
 25→    ).as("login");
 26→
 27→    // Login
 28→    cy.login("login user");
 29→
 30→    // Ensure correct login request responds before checking page for username
 31→    cy.wait("@login").its("request.body.username").should("eq", "login user");
 32→
 33→    // Confirm username appears on the page other than in username input
 34→    cy.contains(":not(input)", "login user").should("exist");
 35→  });
 36→
 37→  it("should logout", () => {
 38→    // Login
 39→    cy.login("logout user");
 40→
 41→    // Confirm username appears on the page other than in username input
 42→    cy.contains(":not(input)", "logout user").should("exist");
 43→
 44→    // Intercept logout request
 45→    cy.intercept(
 46→      "DELETE",
 47→      `${Cypress.env("DATABASE_HOST")}${Cypress.env("AUTH_PATH")}`
 48→    ).as("logout");
 49→
 50→    // Logout
 51→    cy.logout();
 52→
 53→    // Confirm username does not appear on the page
 54→    cy.contains("logout user").should("not.exist");
 55→
 56→    // Confirm correct logout request was sent
 57→    cy.wait("@logout").its("response.statusCode").should("eq", 204);
 58→  });
 59→});
