     1→package server
     2→
     3→import (
     4→	"encoding/json"
     5→	"fmt"
     6→	"io"
     7→	"net/http"
     8→	"net/url"
     9→	"strings"
    10→	"time"
    11→
    12→	"owldb-reference/auth"
    13→	"owldb-reference/db"
    14→	"owldb-reference/jsondata"
    15→)
    16→
    17→type Handler struct {
    18→	dbm    *db.DatabaseManager
    19→	tm     *auth.TokenManager
    20→	sm     *SubscriptionManager
    21→	schema jsondata.Validator
    22→}
    23→
    24→func NewHandler(dbm *db.DatabaseManager, tm *auth.TokenManager, sm *SubscriptionManager, schema jsondata.Validator) *Handler {
    25→	return &Handler{
    26→		dbm:    dbm,
    27→		tm:     tm,
    28→		sm:     sm,
    29→		schema: schema,
    30→	}
    31→}
    32→
    33→func (h *Handler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
    34→	w.Header().Set("Access-Control-Allow-Origin", "*")
    35→	w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, PATCH, DELETE, OPTIONS")
    36→	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type, Accept")
    37→
    38→	path := r.URL.Path
    39→
    40→	if path == "/auth" || path == "/auth/" {
    41→		h.handleAuth(w, r)
    42→		return
    43→	}
    44→
    45→	if strings.HasPrefix(path, "/v1/") || path == "/v1" {
    46→		// OPTIONS doesn't require auth
    47→		if r.Method == http.MethodOptions {
    48→			h.handleOptions(w, r)
    49→			return
    50→		}
    51→
    52→		// Authenticate
    53→		username, ok := h.authenticate(w, r)
    54→		if !ok {
    55→			return
    56→		}
    57→
    58→		h.handleV1(w, r, username)
    59→		return
    60→	}
    61→
    62→	// Default: return something for waitForServer health check
    63→	if path == "/" {
    64→		w.WriteHeader(http.StatusOK)
    65→		return
    66→	}
    67→
    68→	writeError(w, http.StatusNotFound, "not found")
    69→}
    70→
    71→func (h *Handler) authenticate(w http.ResponseWriter, r *http.Request) (string, bool) {
    72→	authHeader := r.Header.Get("Authorization")
    73→	if authHeader == "" {
    74→		writeError(w, http.StatusUnauthorized, "missing authorization header")
    75→		return "", false
    76→	}
    77→
    78→	if !strings.HasPrefix(authHeader, "Bearer ") {
    79→		writeError(w, http.StatusUnauthorized, "invalid authorization format")
    80→		return "", false
    81→	}
    82→
    83→	token := strings.TrimPrefix(authHeader, "Bearer ")
    84→	username, valid := h.tm.ValidateToken(token)
    85→	if !valid {
    86→		writeError(w, http.StatusUnauthorized, "invalid or expired token")
    87→		return "", false
    88→	}
    89→
    90→	return username, true
    91→}
    92→
    93→func (h *Handler) handleAuth(w http.ResponseWriter, r *http.Request) {
    94→	switch r.Method {
    95→	case http.MethodPost:
    96→		h.handleLogin(w, r)
    97→	case http.MethodDelete:
    98→		h.handleLogout(w, r)
    99→	case http.MethodOptions:
   100→		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
   101→		w.WriteHeader(http.StatusOK)
   102→	default:
   103→		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
   104→	}
   105→}
   106→
   107→func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
   108→	body, err := io.ReadAll(r.Body)
   109→	if err != nil {
   110→		writeError(w, http.StatusBadRequest, "failed to read body")
   111→		return
   112→	}
   113→
   114→	var req map[string]string
   115→	if err := json.Unmarshal(body, &req); err != nil {
   116→		writeError(w, http.StatusBadRequest, "invalid JSON")
   117→		return
   118→	}
   119→
   120→	username, ok := req["username"]
   121→	if !ok || username == "" {
   122→		writeError(w, http.StatusBadRequest, "missing username")
   123→		return
   124→	}
   125→
   126→	token := h.tm.Login(username)
   127→	writeJSON(w, http.StatusOK, map[string]string{"token": token})
   128→}
   129→
   130→func (h *Handler) handleLogout(w http.ResponseWriter, r *http.Request) {
   131→	authHeader := r.Header.Get("Authorization")
   132→	if authHeader == "" || !strings.HasPrefix(authHeader, "Bearer ") {
   133→		writeError(w, http.StatusUnauthorized, "missing or invalid authorization")
   134→		return
   135→	}
   136→
   137→	token := strings.TrimPrefix(authHeader, "Bearer ")
   138→	h.tm.Logout(token)
   139→	w.WriteHeader(http.StatusNoContent)
   140→}
   141→
   142→func (h *Handler) handleOptions(w http.ResponseWriter, r *http.Request) {
   143→	path := r.URL.Path
   144→	resourcePath := strings.TrimPrefix(path, "/v1/")
   145→
   146→	isCollection := strings.HasSuffix(resourcePath, "/")
   147→
   148→	if isCollection {
   149→		w.Header().Set("Allow", "GET, PUT, POST, DELETE, OPTIONS")
   150→	} else {
   151→		w.Header().Set("Allow", "GET, PUT, DELETE, PATCH, OPTIONS")
   152→	}
   153→
   154→	w.Header().Set("Access-Control-Allow-Origin", "*")
   155→	w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, PATCH, DELETE, OPTIONS")
   156→	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type, Accept")
   157→	w.WriteHeader(http.StatusOK)
   158→}
   159→
   160→// docPath strips the /v1/<dbname> prefix from a full path,
   161→// returning just the document path (e.g., "/Workspace/channels/General").
   162→// P2 (m3ssag1n8) expects paths without the database prefix.
   163→func docPath(fullPath string) string {
   164→	// fullPath looks like /v1/dbname/... or /v1/dbname
   165→	p := strings.TrimPrefix(fullPath, "/v1/")
   166→	if idx := strings.Index(p, "/"); idx >= 0 {
   167→		return p[idx:]
   168→	}
   169→	return "/"
   170→}
   171→
   172→func (h *Handler) handleV1(w http.ResponseWriter, r *http.Request, username string) {
   173→	rawPath := strings.TrimPrefix(r.URL.Path, "/v1/")
   174→	if rawPath == "" || rawPath == "/" {
   175→		writeError(w, http.StatusBadRequest, "empty path")
   176→		return
   177→	}
   178→
   179→	isCollection := strings.HasSuffix(rawPath, "/")
   180→	mode := r.URL.Query().Get("mode")
   181→
   182→	// Handle subscribe mode
   183→	if mode == "subscribe" {
   184→		h.handleSubscribe(w, r, rawPath, username)
   185→		return
   186→	}
   187→
   188→	switch r.Method {
   189→	case http.MethodGet:
   190→		h.handleGet(w, r, rawPath, isCollection, username)
   191→	case http.MethodPut:
   192→		h.handlePut(w, r, rawPath, isCollection, mode, username)
   193→	case http.MethodPost:
   194→		h.handlePost(w, r, rawPath, isCollection, username)
   195→	case http.MethodDelete:
   196→		h.handleDelete(w, r, rawPath, isCollection, username)
   197→	case http.MethodPatch:
   198→		h.handlePatch(w, r, rawPath, username)
   199→	default:
   200→		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
   201→	}
   202→}
   203→
   204→func (h *Handler) handleGet(w http.ResponseWriter, r *http.Request, rawPath string, isCollection bool, username string) {
   205→	cleanPath := strings.Trim(rawPath, "/")
   206→	parts := splitAndDecode(cleanPath)
   207→
   208→	if len(parts) == 0 {
   209→		writeError(w, http.StatusBadRequest, "empty path")
   210→		return
   211→	}
   212→
   213→	dbName := parts[0]
   214→	dbCol, exists := h.dbm.GetDatabase(dbName)
   215→	if !exists {
   216→		writeError(w, http.StatusNotFound, "database not found")
   217→		return
   218→	}
   219→
   220→	// Database-level GET (collection of top-level docs)
   221→	if len(parts) == 1 {
   222→		intervalStr := r.URL.Query().Get("interval")
   223→		h.getCollection(w, dbCol, "/v1/"+dbName, intervalStr)
   224→		return
   225→	}
   226→
   227→	// Navigate to target
   228→	col, doc, docName, colPath, err := h.navigatePath(dbCol, parts[1:], "/v1/"+dbName)
   229→	if err != nil {
   230→		writeError(w, http.StatusNotFound, err.Error())
   231→		return
   232→	}
   233→
   234→	if isCollection {
   235→		if col == nil {
   236→			writeError(w, http.StatusNotFound, "collection not found")
   237→			return
   238→		}
   239→		intervalStr := r.URL.Query().Get("interval")
   240→		h.getCollection(w, col, colPath, intervalStr)
   241→		return
   242→	}
   243→
   244→	if doc == nil {
   245→		writeError(w, http.StatusNotFound, "document not found")
   246→		return
   247→	}
   248→
   249→	resp, err := doc.ToResponse("/v1/" + cleanPath)
   250→	if err != nil {
   251→		writeError(w, http.StatusInternalServerError, err.Error())
   252→		return
   253→	}
   254→	_ = docName
   255→	writeJSON(w, http.StatusOK, resp)
   256→}
   257→
   258→func (h *Handler) getCollection(w http.ResponseWriter, col *db.Collection, basePath string, intervalStr string) {
   259→	low, high, lowInc, highInc := parseInterval(intervalStr)
   260→	docs := col.ListDocuments(low, high, lowInc, highInc)
   261→
   262→	result := make([]db.DocumentResponse, 0, len(docs))
   263→	for _, d := range docs {
   264→		docPath := basePath + "/" + d.Name
   265→		// Trim any double slashes
   266→		docPath = strings.ReplaceAll(docPath, "//", "/")
   267→		resp, err := d.Doc.ToResponse(docPath)
   268→		if err != nil {
   269→			continue
   270→		}
   271→		result = append(result, resp)
   272→	}
   273→
   274→	writeJSON(w, http.StatusOK, result)
   275→}
   276→
   277→func (h *Handler) handlePut(w http.ResponseWriter, r *http.Request, rawPath string, isCollection bool, mode string, username string) {
   278→	cleanPath := strings.Trim(rawPath, "/")
   279→	parts := splitAndDecode(cleanPath)
   280→
   281→	if len(parts) == 0 {
   282→		writeError(w, http.StatusBadRequest, "empty path")
   283→		return
   284→	}
   285→
   286→	dbName := parts[0]
   287→
   288→	// Creating a database (path is just the db name with trailing slash)
   289→	if len(parts) == 1 && isCollection {
   290→		_, err := h.dbm.CreateDatabase(dbName)
   291→		if err != nil {
   292→			writeError(w, http.StatusConflict, "database already exists")
   293→			return
   294→		}
   295→		// Database-level URI keeps the full /v1/<dbname> path
   296→		writeJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbName})
   297→		return
   298→	}
