 31→func (iv *Interval) Contains(name string) bool {
 32→	if iv == nil {
 33→		return true
 34→	}
 35→	if iv.Low != "" {
 36→		if iv.LowInclusive {
 37→			if name < iv.Low {
 38→				return false
 39→			}
 40→		} else {
 41→			if name <= iv.Low {
 42→				return false
 43→			}
 44→		}
 45→	}
 46→	if iv.High != "" {
 47→		if iv.HighInclusive {
 48→			if name > iv.High {
 49→				return false
 50→			}
 51→		} else {
 52→			if name >= iv.High {
 53→				return false
 54→			}
 55→		}
 56→	}
 57→	return true
 58→}
