204→func WriteSSEStream(w http.ResponseWriter, r *http.Request, sub *Subscriber) {
205→	flusher, ok := w.(http.Flusher)
206→	if !ok {
207→		http.Error(w, "streaming not supported", http.StatusInternalServerError)
208→		return
209→	}
210→
211→	w.Header().Set("Content-Type", "text/event-stream")
212→	w.Header().Set("Cache-Control", "no-cache")
213→	w.Header().Set("Connection", "keep-alive")
214→	w.Header().Set("Access-Control-Allow-Origin", "*")
215→	w.WriteHeader(http.StatusOK)
216→	flusher.Flush()
217→
218→	keepAlive := time.NewTicker(15 * time.Second)
219→	defer keepAlive.Stop()
220→
221→	ctx := r.Context()
222→
223→	for {
224→		select {
225→		case event, ok := <-sub.ch:
226→			if !ok {
227→				return
228→			}
229→			dataBytes, err := json.Marshal(event.Data)
230→			if err != nil {
231→				continue
232→			}
233→			fmt.Fprintf(w, "event: %s\n", event.EventType)
234→			fmt.Fprintf(w, "data: %s\n", string(dataBytes))
235→			fmt.Fprintf(w, "id: %s\n\n", event.ID)
236→			flusher.Flush()
237→
238→		case <-keepAlive.C:
239→			fmt.Fprintf(w, ": keepalive\n\n")
240→			flusher.Flush()
241→
242→		case <-ctx.Done():
243→			sub.once.Do(func() { close(sub.done) })
244→			return
245→		}
246→	}
247→}
