    10→// navigateVisitor traverses into a JSON object following a path, and applies an operation at the leaf
    11→type navigateVisitor struct {
    12→	pathParts []string
    13→	depth     int
    14→	op        func(jsondata.JSONValue) (jsondata.JSONValue, error)
    15→}
    16→
    17→func (v *navigateVisitor) Map(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
    18→	key := v.pathParts[v.depth]
    19→
    20→	if v.depth == len(v.pathParts)-1 {
    21→		// We're at the target level
    22→		val, ok := m[key]
    23→		if !ok {
    24→			// For ObjectAdd, we need to handle the key not existing differently
    25→			result, err := v.op(jsondata.JSONValue{})
    26→			if err != nil {
    27→				return jsondata.JSONValue{}, err
    28→			}
    29→			m[key] = result
    30→			return rebuildMap(m)
    31→		}
    32→		result, err := v.op(val)
    33→		if err != nil {
    34→			return jsondata.JSONValue{}, err
    35→		}
    36→		m[key] = result
    37→		return rebuildMap(m)
    38→	}
    39→
    40→	// Navigate deeper
    41→	val, ok := m[key]
    42→	if !ok {
    43→		return jsondata.JSONValue{}, fmt.Errorf("path not found: %s", v.pathParts[v.depth])
    44→	}
    45→
    46→	v.depth++
    47→	result, err := jsondata.Accept(val, v)
    48→	if err != nil {
    49→		return jsondata.JSONValue{}, err
    50→	}
    51→	m[key] = result
    52→	return rebuildMap(m)
    53→}
    54→
    55→func (v *navigateVisitor) Slice(s []jsondata.JSONValue) (jsondata.JSONValue, error) {
    56→	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into array with key %s", v.pathParts[v.depth])
    57→}
    58→
    59→func (v *navigateVisitor) Bool(b bool) (jsondata.JSONValue, error) {
    60→	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into bool")
    61→}
    62→
    63→func (v *navigateVisitor) Float64(f float64) (jsondata.JSONValue, error) {
    64→	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into number")
    65→}
    66→
    67→func (v *navigateVisitor) String(s string) (jsondata.JSONValue, error) {
    68→	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into string")
    69→}
    70→
    71→func (v *navigateVisitor) Null() (jsondata.JSONValue, error) {
    72→	return jsondata.JSONValue{}, fmt.Errorf("cannot navigate into null")
    73→}
