    75→func rebuildMap(m map[string]jsondata.JSONValue) (jsondata.JSONValue, error) {
    76→	raw := make(map[string]interface{})
    77→	for k, v := range m {
    78→		b, err := json.Marshal(v)
    79→		if err != nil {
    80→			return jsondata.JSONValue{}, err
    81→		}
    82→		var val interface{}
    83→		json.Unmarshal(b, &val)
    84→		raw[k] = val
    85→	}
    86→	return jsondata.NewJSONValue(raw)
    87→}
