215→func ApplyPatches(doc *Document, patches []PatchOp, username string) PatchResult {
216→	doc.mu.Lock()
217→	defer doc.mu.Unlock()
218→
219→	// Work on the document data
220→	currentData := doc.Data
221→
222→	for _, patch := range patches {
223→		var err error
224→		currentData, err = applyOnePatch(currentData, patch)
225→		if err != nil {
226→			return PatchResult{
227→				PatchFailed: true,
228→				Message:     err.Error(),
229→			}
230→		}
231→	}
232→
233→	doc.Data = currentData
234→	now := float64(time.Now().UnixMilli())
235→	doc.Meta.LastModifiedBy = username
236→	doc.Meta.LastModifiedAt = now
237→
238→	return PatchResult{
239→		PatchFailed: false,
240→		Message:     "patch applied",
241→	}
242→}
