244→func applyOnePatch(data jsondata.JSONValue, patch PatchOp) (jsondata.JSONValue, error) {
245→	pathParts := parsePatchPath(patch.Path)
246→	if len(pathParts) == 0 {
247→		return data, fmt.Errorf("empty path")
248→	}
249→
250→	switch patch.Op {
251→	case "ArrayAdd":
252→		return applyArrayAdd(data, pathParts, patch.Value)
253→	case "ArrayRemove":
254→		return applyArrayRemove(data, pathParts, patch.Value)
255→	case "ObjectAdd":
256→		return applyObjectAdd(data, pathParts, patch.Value)
257→	default:
258→		return data, fmt.Errorf("unknown operation: %s", patch.Op)
259→	}
260→}
