 22→// TestResult represents the outcome of a single test
 23→type TestResult struct {
 24→	Name     string        `json:"name"`
 25→	Passed   bool          `json:"passed"`
 26→	Duration time.Duration `json:"duration"`
 27→	Error    string        `json:"error,omitempty"`
 28→	Details  string        `json:"details,omitempty"`
 29→}
