// ==================== EVENT HANDLERS ====================

async function handleLogin(): Promise<void> {
  const input = getEl("username-input") as HTMLInputElement;
  const username = input.value.trim();
  if (!username) return;

  const loginError = getEl("login-error");
  loginError.textContent = "";

  try {
    await doLogin(username);
    getEl("current-user").textContent = username;
    showApp();

    // Fetch workspaces with bearer token
    await loadWorkspaces();
    renderWorkspaces();
  } catch (err) {
    loginError.textContent =
      err instanceof Error ? err.message : "Login failed";
  }
}

async function handleLogout(): Promise<void> {
  try {
    await doLogout();
  } catch {
    // Ignore logout errors
  }

  getEl("current-user").textContent = "";
  hidePostsArea();
  hideChannelSection();
  clearError();
  hideApp();

  // Clear inputs
  (getEl("workspace-name-input") as HTMLInputElement).value = "";
  (getEl("channel-name-input") as HTMLInputElement).value = "";
  (getEl("username-input") as HTMLInputElement).value = "";
  getEl("workspace-list").innerHTML = "";
}

async function handleOpenWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  // Close current channel and posts
  hidePostsArea();

  try {
    await loadChannels(name);
    state.currentWorkspace = name;
    showChannelSection();
    renderChannels();
  } catch (err) {
    hideChannelSection();
    state.currentWorkspace = null;
    showError(err instanceof Error ? err.message : "Error: Failed to open workspace");
  }
}

async function handleCreateWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  try {
    await apiCreateWorkspace(name);

    // Refresh workspace list
    await loadWorkspaces();
    renderWorkspaces();

    // Auto-open the new workspace
    await handleOpenWorkspace(name);
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to create workspace");
  }
}

async function handleDeleteWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  try {
    await apiDeleteWorkspace(name);

    // If the deleted workspace was the current one, close it
    if (state.currentWorkspace === name) {
      hidePostsArea();
      hideChannelSection();
      state.currentWorkspace = null;
    }

    // Refresh workspace list
    await loadWorkspaces();
    renderWorkspaces();
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to delete workspace");
  }
}

async function handleOpenChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  // Close current channel
  hidePostsArea();

  try {
    // Verify channel exists by trying to get it
    const res = await apiFetch(
      `${DB_PATH}${encodeURIComponent(state.currentWorkspace)}/channels/${encodeURIComponent(name)}`,
    );
    if (!res.ok) {
      throw new Error(
        "Error: Channel not found or does not exist.",
      );
    }

    state.currentChannel = name;
    showPostsArea();

    // Subscribe to posts via SSE
    subscribeToChannel(state.currentWorkspace, name);
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to open channel");
  }
}

async function handleCreateChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  try {
    await apiCreateChannel(state.currentWorkspace, name);

    // Refresh channel list
    await loadChannels(state.currentWorkspace);
    renderChannels();
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to create channel");
  }
}

async function handleDeleteChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  try {
    await apiDeleteChannel(state.currentWorkspace, name);

    // If the deleted channel was the current one, close it
    if (state.currentChannel === name) {
      hidePostsArea();
    }

    // Refresh channel list
    await loadChannels(state.currentWorkspace);
    renderChannels();
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to delete channel");
  }
}

async function handleCreatePost(): Promise<void> {
  if (!state.currentWorkspace || !state.currentChannel) return;

  const input = getEl("post-input") as HTMLTextAreaElement;
  const msg = input.value;
  if (!msg.trim()) return;

  try {
    await apiCreatePost(
      state.currentWorkspace,
      state.currentChannel,
      msg,
      state.replyParent,
    );
    input.value = "";
    cancelReply();
  } catch (err) {
    showError(err instanceof Error ? err.message : "Error: Failed to create post");
  }
}

function handleReply(postPath: string): void {
  state.replyParent = postPath;
  getEl("reply-info").classList.remove("hidden");
  getEl("reply-label").textContent = "Replying to post...";
  (getEl("post-input") as HTMLTextAreaElement).focus();
}

function cancelReply(): void {
  state.replyParent = "";
  getEl("reply-info").classList.add("hidden");
}

async function handleReact(
  postPath: string,
  reaction: string,
  add: boolean,
): Promise<void> {
  if (!state.username) return;

  try {
    await apiPatchReaction(postPath, reaction, state.username, add);
  } catch (err) {
    slog.error("Failed to update reaction", [
      "error",
      err instanceof Error ? err.message : "unknown",
    ]);
  }
}

// ==================== TOOLBAR HANDLERS ====================

function insertAtCursor(
  textarea: HTMLTextAreaElement,
  before: string,
  after: string,
): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  const text = textarea.value;
  const selected = text.substring(start, end);

  const newText = before + selected + after;
  textarea.value = text.substring(0, start) + newText + text.substring(end);
  textarea.selectionStart = start + before.length;
  textarea.selectionEnd = start + before.length + selected.length;
  textarea.focus();
}

// ==================== INITIALIZATION ====================

function main(): void {
  slog.info("Using database", [
    "database",
    `${DB_HOST}${DB_PATH}`,
  ]);

  const loginDialog = document.getElementById(
    "login-dialog",
  ) as HTMLDialogElement;
  loginDialog.showModal();

  // Login
  getEl("login-btn").addEventListener("click", handleLogin);
  getEl("username-input").addEventListener("keydown", (e) => {
    if ((e as KeyboardEvent).key === "Enter") {
      handleLogin();
    }
  });

  // Logout
  getEl("logout-btn").addEventListener("click", handleLogout);

  // Workspace buttons
  getEl("open-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleOpenWorkspace(name);
  });

  getEl("create-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleCreateWorkspace(name);
  });

  getEl("delete-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleDeleteWorkspace(name);
  });

  getEl("refresh-workspaces-btn").addEventListener("click", async () => {
    try {
      await loadWorkspaces();
      renderWorkspaces();
    } catch (err) {
      showError(
        err instanceof Error ? err.message : "Error: Failed to refresh workspaces",
      );
    }
  });

  // Channel buttons
  getEl("open-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleOpenChannel(name);
  });

  getEl("create-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleCreateChannel(name);
  });

  getEl("delete-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleDeleteChannel(name);
  });

  getEl("refresh-channels-btn").addEventListener("click", async () => {
    if (!state.currentWorkspace) return;
    try {
      await loadChannels(state.currentWorkspace);
      renderChannels();
    } catch (err) {
      showError(
        err instanceof Error ? err.message : "Error: Failed to refresh channels",
      );
    }
  });

  // Post buttons
  getEl("post-btn").addEventListener("click", handleCreatePost);
  getEl("cancel-reply-btn").addEventListener("click", cancelReply);

  // Post input - Enter to submit, Shift+Enter for newline
  getEl("post-input").addEventListener("keydown", (e) => {
    const ke = e as KeyboardEvent;
    if (ke.key === "Enter" && !ke.shiftKey) {
      ke.preventDefault();
      handleCreatePost();
    }
  });

  // Error close
  getEl("error-close-btn").addEventListener("click", clearError);

  // Toolbar buttons
  getEl("bold-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "**", "**");
  });

  getEl("italic-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "*", "*");
  });

  getEl("link-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "[", "](url)");
  });

  // Emoji insert buttons
  document.querySelectorAll(".emoji-insert-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      const emoji = btn.getAttribute("data-emoji") || "";
      const textarea = getEl("post-input") as HTMLTextAreaElement;
      const start = textarea.selectionStart;
      const text = textarea.value;
      textarea.value =
        text.substring(0, start) + emoji + text.substring(start);
      textarea.selectionStart = start + emoji.length;
      textarea.selectionEnd = start + emoji.length;
      textarea.focus();
    });
  });
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

