import { slog } from "./slog";
import { fetchEventSource } from "@microsoft/fetch-event-source";
import Ajv from "ajv";

// ==================== ENVIRONMENT ====================

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

const DB_HOST = process.env.DATABASE_HOST;
const DB_PATH = process.env.DATABASE_PATH;
const AUTH_URL = `${DB_HOST}${process.env.AUTH_PATH}`;

// ==================== SCHEMAS & VALIDATION ====================

const ajv = new Ajv({ allErrors: true });

const PostDocSchema = {
  type: "object" as const,
  required: ["msg"],
  properties: {
    msg: { type: "string" as const },
    parent: { type: "string" as const },
    reactions: {
      type: "object" as const,
      additionalProperties: {
        type: "array" as const,
        items: { type: "string" as const },
      },
    },
    extensions: { type: "object" as const },
  },
  additionalProperties: true,
};

const DocResponseSchema = {
  type: "object" as const,
  required: ["path", "doc", "meta"],
  properties: {
    path: { type: "string" as const },
    doc: { type: "object" as const },
    meta: {
      type: "object" as const,
      required: ["createdBy", "createdAt", "lastModifiedBy", "lastModifiedAt"],
      properties: {
        createdBy: { type: "string" as const },
        createdAt: { type: "number" as const },
        lastModifiedBy: { type: "string" as const },
        lastModifiedAt: { type: "number" as const },
      },
    },
  },
  additionalProperties: true,
};

const AuthResponseSchema = {
  type: "object" as const,
  required: ["token"],
  properties: {
    token: { type: "string" as const },
  },
  additionalProperties: true,
};

const validatePostDoc = ajv.compile(PostDocSchema);
const validateDocResponse = ajv.compile(DocResponseSchema);
const validateAuthResponse = ajv.compile(AuthResponseSchema);

// ==================== TYPES ====================

interface DocMeta {
  createdBy: string;
  createdAt: number;
  lastModifiedBy: string;
  lastModifiedAt: number;
}

interface DocResponse {
  path: string;
  doc: Record<string, unknown>;
  meta: DocMeta;
}

interface PostDoc {
  msg: string;
  parent: string;
  reactions?: Record<string, string[]>;
}

// ==================== STATE ====================

const state = {
  token: null as string | null,
  username: null as string | null,
  currentWorkspace: null as string | null,
  currentChannel: null as string | null,
  workspaces: [] as DocResponse[],
  channels: [] as DocResponse[],
  posts: new Map<string, DocResponse>(),
  replyParent: "" as string,
  sseController: null as AbortController | null,
};

// ==================== HELPERS ====================

function normPath(p: string): string {
  return p.startsWith("/") ? p.substring(1) : p;
}

function docName(path: string): string {
  const parts = normPath(path).split("/");
  return decodeURIComponent(parts[parts.length - 1]);
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

const EMOJI_MAP: Record<string, string> = {
  ":smile:":
    '<iconify-icon icon="mdi:emoticon-happy" aria-label="smile"></iconify-icon>',
  ":frown:":
    '<iconify-icon icon="mdi:emoticon-sad" aria-label="frown"></iconify-icon>',
  ":like:":
    '<iconify-icon icon="mdi:thumb-up" aria-label="like"></iconify-icon>',
  ":celebrate:":
    '<iconify-icon icon="mdi:party-popper" aria-label="celebrate"></iconify-icon>',
};

function formatPostContent(msg: string): string {
  let html = escapeHtml(msg);

  // Links: [text](url)
  html = html.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener">$1</a>',
  );

  // Bold: **text**
  html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  // Italic: *text*
  html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");

  // Emoji reactions
  html = html.replace(/:([a-z-]+):/g, (match) => {
    return EMOJI_MAP[match] || match;
  });

  // Newlines
  html = html.replace(/\n/g, "<br>");

  return html;
}

function formatTime(timestamp: number): string {
  const date = new Date(timestamp);
  return date.toLocaleString();
}

function el<K extends keyof HTMLElementTagNameMap>(
  tag: K,
  attrs?: Record<string, string>,
  ...children: (Node | string)[]
): HTMLElementTagNameMap[K] {
  const elem = document.createElement(tag);
  if (attrs) {
    for (const [key, val] of Object.entries(attrs)) {
      elem.setAttribute(key, val);
    }
  }
  for (const child of children) {
    if (typeof child === "string") {
      elem.appendChild(document.createTextNode(child));
    } else {
      elem.appendChild(child);
    }
  }
  return elem;
}

// ==================== DOM REFERENCES ====================

function getEl(id: string): HTMLElement {
  return document.getElementById(id)!;
}

// ==================== API ====================

async function apiFetch(
  path: string,
  method: string = "GET",
  body?: unknown,
): Promise<Response> {
  const url = `${DB_HOST}${path}`;
  const headers: Record<string, string> = {};

  if (state.token) {
    headers["Authorization"] = `Bearer ${state.token}`;
  }

  if (body !== undefined) {
    headers["Content-Type"] = "application/json";
  }

  return fetch(url, {
    method,
    headers,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  });
}

async function doLogin(username: string): Promise<void> {
  const response = await fetch(AUTH_URL, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username }),
  });

  if (!response.ok) {
    throw new Error(`Login failed: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!validateAuthResponse(data)) {
    throw new Error("Invalid auth response");
  }

  const authData = data as { token: string };
  state.token = authData.token;
  state.username = username;
}

async function doLogout(): Promise<void> {
  if (!state.token) return;

  await fetch(AUTH_URL, {
    method: "DELETE",
    headers: { Authorization: `Bearer ${state.token}` },
  });

  state.token = null;
  state.username = null;
  state.currentWorkspace = null;
  state.currentChannel = null;
  state.workspaces = [];
  state.channels = [];
  state.posts.clear();
  state.replyParent = "";
  closeSse();
}

async function loadWorkspaces(): Promise<void> {
  const response = await apiFetch(DB_PATH);
  if (!response.ok) {
    throw new Error(`Failed to fetch workspaces: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!Array.isArray(data)) {
    throw new Error("Invalid workspace list response");
  }

  state.workspaces = data.filter((item: unknown) =>
    validateDocResponse(item),
  ) as DocResponse[];
}

async function loadChannels(workspace: string): Promise<void> {
  const response = await apiFetch(
    `${DB_PATH}${encodeURIComponent(workspace)}/channels/`,
  );
  if (!response.ok) {
    throw new Error(
      `Error: Could not load channels. Workspace not found or does not exist.`,
    );
  }

  const data: unknown = await response.json();
  if (!Array.isArray(data)) {
    throw new Error("Invalid channel list response");
  }

  state.channels = data.filter((item: unknown) =>
    validateDocResponse(item),
  ) as DocResponse[];
}

async function apiCreateWorkspace(name: string): Promise<void> {
  const res = await apiFetch(
    `${DB_PATH}${encodeURIComponent(name)}?mode=nooverwrite`,
    "PUT",
    {},
  );

  if (res.status === 409) {
    throw new Error("Error: Workspace already exists (conflict)");
  }

  if (!res.ok) {
    const errBody = (await res.json().catch(() => ({}))) as Record<
      string,
      unknown
    >;
    throw new Error(
      (errBody.error as string) ||
        `Error: Failed to create workspace: ${res.statusText}`,
    );
  }

  // Create channels collection
  await apiFetch(
    `${DB_PATH}${encodeURIComponent(name)}/channels/`,
    "PUT",
  );
}

async function apiDeleteWorkspace(name: string): Promise<void> {
  const res = await apiFetch(
    `${DB_PATH}${encodeURIComponent(name)}`,
    "DELETE",
  );

  if (!res.ok) {
    throw new Error(
      `Error: Failed to delete workspace. It may not found or does not exist.`,
    );
  }
}

async function apiCreateChannel(
  workspace: string,
  name: string,
): Promise<void> {
  const res = await apiFetch(
    `${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}?mode=nooverwrite`,
    "PUT",
    {},
  );

  if (res.status === 409) {
    throw new Error("Error: Channel already exists (conflict)");
  }

  if (!res.ok) {
    const errBody = (await res.json().catch(() => ({}))) as Record<
      string,
      unknown
    >;
    throw new Error(
      (errBody.error as string) ||
        `Error: Failed to create channel: ${res.statusText}`,
    );
  }

  // Create posts collection
  await apiFetch(
    `${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    "PUT",
  );
}

async function apiDeleteChannel(
  workspace: string,
  name: string,
): Promise<void> {
  const res = await apiFetch(
    `${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    "DELETE",
  );

  if (!res.ok) {
    throw new Error(
      `Error: Failed to delete channel. It may not found or does not exist.`,
    );
  }
}

async function apiCreatePost(
  workspace: string,
  channel: string,
  msg: string,
  parent: string = "",
): Promise<void> {
  const res = await apiFetch(
    `${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    "POST",
    { msg, parent },
  );

  if (!res.ok) {
    throw new Error(`Error: Failed to create post: ${res.statusText}`);
  }
}

async function apiPatchReaction(
  postPath: string,
  reaction: string,
  username: string,
  add: boolean,
): Promise<void> {
  const encoded = normPath(postPath)
    .split("/")
    .map(encodeURIComponent)
    .join("/");
  const url = `${DB_HOST}${DB_PATH}${encoded}`;

  const ops = add
    ? [
        { op: "ObjectAdd", path: "/reactions", value: {} },
        {
          op: "ObjectAdd",
          path: `/reactions/${reaction}`,
          value: [] as string[],
        },
        { op: "ArrayAdd", path: `/reactions/${reaction}`, value: username },
      ]
    : [{ op: "ArrayRemove", path: `/reactions/${reaction}`, value: username }];

  const res = await fetch(url, {
    method: "PATCH",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${state.token}`,
    },
    body: JSON.stringify(ops),
  });

  if (!res.ok) {
    throw new Error(`Error: Failed to update reaction: ${res.statusText}`);
  }
}

// ==================== SSE ====================

function closeSse(): void {
  if (state.sseController) {
    state.sseController.abort();
    state.sseController = null;
  }
}

function subscribeToChannel(workspace: string, channel: string): void {
  closeSse();
  state.posts.clear();

  state.sseController = new AbortController();
  const url = `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/?mode=subscribe`;

  fetchEventSource(url, {
    method: "GET",
    headers: {
      Authorization: `Bearer ${state.token}`,
    },
    signal: state.sseController.signal,
    openWhenHidden: true,
    onmessage(event) {
      if (!event.data) return;

      try {
        const doc: unknown = JSON.parse(event.data);
        if (!validateDocResponse(doc)) return;

        const docResp = doc as DocResponse;

        if (event.event === "update" || event.event === "") {
          const path = normPath(docResp.path);
          const existing = state.posts.has(path);
          state.posts.set(path, docResp);

          if (existing) {
            updatePostInDom(path, docResp);
          } else {
            scheduleFullRender();
          }
        } else if (event.event === "delete") {
          state.posts.delete(normPath(docResp.path));
          scheduleFullRender();
        }
      } catch {
        slog.warn("Failed to parse SSE event data");
      }
    },
    onerror() {
      // Stop reconnecting
      throw new Error("SSE connection closed");
    },
  }).catch(() => {
    // Silently ignore abort errors
  });
}

// ==================== POST HIERARCHY ====================

interface FlatPost {
  path: string;
  doc: PostDoc;
  meta: DocMeta;
  depth: number;
}

function buildPostTree(): FlatPost[] {
  const allPosts: { path: string; docResp: DocResponse }[] = [];

  for (const [path, docResp] of state.posts) {
    allPosts.push({ path, docResp });
  }

  // Sort by creation time
  allPosts.sort((a, b) => a.docResp.meta.createdAt - b.docResp.meta.createdAt);

  // Build parent -> children map
  const childrenMap = new Map<string, typeof allPosts>();
  const roots: typeof allPosts = [];

  for (const post of allPosts) {
    const rawDoc = post.docResp.doc;
    const parent = (rawDoc.parent as string) || "";

    if (!parent) {
      roots.push(post);
    } else {
      const normParent = normPath(parent);
      if (!childrenMap.has(normParent)) {
        childrenMap.set(normParent, []);
      }
      childrenMap.get(normParent)!.push(post);
    }
  }

  // DFS to produce flat ordered list
  const result: FlatPost[] = [];

  function dfs(posts: typeof allPosts, depth: number): void {
    for (const p of posts) {
      const rawDoc = p.docResp.doc;

      // Validate post document
      if (!validatePostDoc(rawDoc)) {
        slog.warn("Skipping invalid post document", ["path", p.path]);
        continue;
      }

      const postDoc: PostDoc = {
        msg: rawDoc.msg as string,
        parent: (rawDoc.parent as string) || "",
        reactions: rawDoc.reactions as Record<string, string[]> | undefined,
      };

      result.push({
        path: p.path,
        doc: postDoc,
        meta: p.docResp.meta,
        depth,
      });

      const children = childrenMap.get(p.path) || [];
      dfs(children, depth + 1);
    }
  }

  dfs(roots, 0);
  return result;
}

// ==================== RENDERING ====================

let renderPending = false;

function scheduleFullRender(): void {
  if (!renderPending) {
    renderPending = true;
    requestAnimationFrame(() => {
      renderAllPosts();
      renderPending = false;
    });
  }
}

function renderWorkspaces(): void {
  const list = getEl("workspace-list");
  list.innerHTML = "";

  for (const ws of state.workspaces) {
    const name = docName(ws.path);
    const item = el("div", { class: "workspace-item", role: "listitem" });
    const nameSpan = el("span", {}, name);
    item.appendChild(nameSpan);
    item.addEventListener("click", () => {
      (getEl("workspace-name-input") as HTMLInputElement).value = name;
      handleOpenWorkspace(name);
    });
    list.appendChild(item);
  }
}

function renderChannels(): void {
  const list = getEl("channel-list");
  list.innerHTML = "";

  for (const ch of state.channels) {
    const name = docName(ch.path);
    const item = el("div", { class: "channel-item", role: "listitem" });
    const nameSpan = el("span", {}, name);
    item.appendChild(nameSpan);
    item.addEventListener("click", () => {
      (getEl("channel-name-input") as HTMLInputElement).value = name;
      handleOpenChannel(name);
    });
    list.appendChild(item);
  }
}

function createPostElement(fp: FlatPost): HTMLElement {
  const postEl = el("div", {
    class: "post-item",
    "data-path": fp.path,
    style: `margin-left: ${fp.depth * 30}px;`,
  });

  // Header
  const header = el("div", { class: "post-header" });
  header.appendChild(el("span", { class: "post-author" }, fp.meta.createdBy));
  header.appendChild(
    el("span", { class: "post-time" }, formatTime(fp.meta.createdAt)),
  );
  postEl.appendChild(header);

  // Content
  const content = el("div", { class: "post-content" });
  content.innerHTML = formatPostContent(fp.doc.msg);
  postEl.appendChild(content);

  // Reactions
  const reactionsDiv = el("div", { class: "post-reactions" });
  renderReactionButtons(reactionsDiv, fp);
  postEl.appendChild(reactionsDiv);

  // Actions
  const actions = el("div", { class: "post-actions" });
  const replyBtn = el("button", { class: "reply-btn" }, "Reply");
  replyBtn.addEventListener("click", (e) => {
    e.stopPropagation();
    handleReply(fp.path);
  });
  actions.appendChild(replyBtn);
  postEl.appendChild(actions);

  return postEl;
}

function renderReactionButtons(container: HTMLElement, fp: FlatPost): void {
  const reactions = fp.doc.reactions || {};
  const reactionTypes = [":smile:", ":frown:", ":like:", ":celebrate:"];
  const iconMap: Record<string, string> = {
    ":smile:": "mdi:emoticon-happy",
    ":frown:": "mdi:emoticon-sad",
    ":like:": "mdi:thumb-up",
    ":celebrate:": "mdi:party-popper",
  };

  for (const reaction of reactionTypes) {
    const users = reactions[reaction] || [];
    const count = users.length;
    const isActive = state.username ? users.includes(state.username) : false;

    const btn = el("button", {
      class: `reaction-btn${isActive ? " active" : ""}`,
      "data-reaction": reaction,
    });

    const icon = document.createElement("iconify-icon");
    icon.setAttribute("icon", iconMap[reaction]);
    icon.setAttribute("aria-label", reaction.replace(/:/g, ""));
    btn.appendChild(icon);

    const countSpan = el("span", { class: "reaction-count" }, String(count));
    btn.appendChild(countSpan);

    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      handleReact(fp.path, reaction, !isActive);
    });

    container.appendChild(btn);
  }
}

function updatePostInDom(path: string, docResp: DocResponse): void {
  const cssPath = CSS.escape(path);
  const existing = document.querySelector(`[data-path="${cssPath}"]`);
  if (!existing) {
    scheduleFullRender();
    return;
  }

  const rawDoc = docResp.doc;
  if (!validatePostDoc(rawDoc)) return;

  const postDoc: PostDoc = {
    msg: rawDoc.msg as string,
    parent: (rawDoc.parent as string) || "",
    reactions: rawDoc.reactions as Record<string, string[]> | undefined,
  };

  // Update content
  const contentEl = existing.querySelector(".post-content");
  if (contentEl) {
    contentEl.innerHTML = formatPostContent(postDoc.msg);
  }

  // Update reactions
  const reactionsEl = existing.querySelector(".post-reactions");
  if (reactionsEl) {
    reactionsEl.innerHTML = "";
    const style = (existing as HTMLElement).style.marginLeft;
    const depth = style ? parseInt(style) / 30 : 0;
    renderReactionButtons(reactionsEl as HTMLElement, {
      path,
      doc: postDoc,
      meta: docResp.meta,
      depth,
    });
  }
}

function renderAllPosts(): void {
  const container = getEl("posts-container");
  container.innerHTML = "";

  const flatPosts = buildPostTree();

  for (const fp of flatPosts) {
    container.appendChild(createPostElement(fp));
  }
}

// ==================== ERROR DISPLAY ====================

function showError(msg: string): void {
  const bar = getEl("error-bar");
  const msgEl = getEl("error-message");
  msgEl.textContent = msg;
  bar.classList.remove("hidden");
}

function clearError(): void {
  const bar = getEl("error-bar");
  bar.classList.add("hidden");
}

// ==================== UI STATE ====================

function showApp(): void {
  getEl("app").classList.remove("hidden");
  (document.getElementById("login-dialog") as HTMLDialogElement).close();
}

function hideApp(): void {
  getEl("app").classList.add("hidden");
  getEl("channel-section").classList.add("hidden");
  getEl("posts-area").classList.add("hidden");
  (document.getElementById("login-dialog") as HTMLDialogElement).showModal();
}

function showChannelSection(): void {
  getEl("channel-section").classList.remove("hidden");
  getEl("workspace-title").textContent = `# ${state.currentWorkspace}`;
}

function hideChannelSection(): void {
  getEl("channel-section").classList.add("hidden");
  getEl("channel-list").innerHTML = "";
  getEl("workspace-title").textContent = "";
}

function showPostsArea(): void {
  getEl("posts-area").classList.remove("hidden");
  getEl("channel-title").textContent = `# ${state.currentChannel}`;
}

function hidePostsArea(): void {
  getEl("posts-area").classList.add("hidden");
  getEl("posts-container").innerHTML = "";
  getEl("channel-title").textContent = "";
  closeSse();
  state.posts.clear();
  state.currentChannel = null;
  state.replyParent = "";
  getEl("reply-info").classList.add("hidden");
}

// ==================== EVENT HANDLERS ====================

async function handleLogin(): Promise<void> {
  const input = getEl("username-input") as HTMLInputElement;
  const username = input.value.trim();
  if (!username) return;

  const loginError = getEl("login-error");
  loginError.textContent = "";

  try {
    await doLogin(username);
    getEl("current-user").textContent = username;
    showApp();

    // Fetch workspaces with bearer token
    await loadWorkspaces();
    renderWorkspaces();
  } catch (err) {
    loginError.textContent =
      err instanceof Error ? err.message : "Login failed";
  }
}

async function handleLogout(): Promise<void> {
  try {
    await doLogout();
  } catch {
    // Ignore logout errors
  }

  getEl("current-user").textContent = "";
  hidePostsArea();
  hideChannelSection();
  clearError();
  hideApp();

  // Clear inputs
  (getEl("workspace-name-input") as HTMLInputElement).value = "";
  (getEl("channel-name-input") as HTMLInputElement).value = "";
  (getEl("username-input") as HTMLInputElement).value = "";
  getEl("workspace-list").innerHTML = "";
}

async function handleOpenWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  // Close current channel and posts
  hidePostsArea();

  try {
    await loadChannels(name);
    state.currentWorkspace = name;
    showChannelSection();
    renderChannels();
  } catch (err) {
    hideChannelSection();
    state.currentWorkspace = null;
    showError(
      err instanceof Error ? err.message : "Error: Failed to open workspace",
    );
  }
}

async function handleCreateWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  try {
    await apiCreateWorkspace(name);

    // Refresh workspace list
    await loadWorkspaces();
    renderWorkspaces();

    // Auto-open the new workspace
    await handleOpenWorkspace(name);
  } catch (err) {
    showError(
      err instanceof Error
        ? err.message
        : "Error: Failed to create workspace",
    );
  }
}

async function handleDeleteWorkspace(name: string): Promise<void> {
  clearError();
  (getEl("workspace-name-input") as HTMLInputElement).value = "";

  try {
    await apiDeleteWorkspace(name);

    // If the deleted workspace was the current one, close it
    if (state.currentWorkspace === name) {
      hidePostsArea();
      hideChannelSection();
      state.currentWorkspace = null;
    }

    // Refresh workspace list
    await loadWorkspaces();
    renderWorkspaces();
  } catch (err) {
    showError(
      err instanceof Error
        ? err.message
        : "Error: Failed to delete workspace",
    );
  }
}

async function handleOpenChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  // Close current channel
  hidePostsArea();

  try {
    // Verify channel exists by trying to get it
    const res = await apiFetch(
      `${DB_PATH}${encodeURIComponent(state.currentWorkspace)}/channels/${encodeURIComponent(name)}`,
    );
    if (!res.ok) {
      throw new Error("Error: Channel not found or does not exist.");
    }

    state.currentChannel = name;
    showPostsArea();

    // Subscribe to posts via SSE
    subscribeToChannel(state.currentWorkspace, name);
  } catch (err) {
    showError(
      err instanceof Error ? err.message : "Error: Failed to open channel",
    );
  }
}

async function handleCreateChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  try {
    await apiCreateChannel(state.currentWorkspace, name);

    // Refresh channel list
    await loadChannels(state.currentWorkspace);
    renderChannels();
  } catch (err) {
    showError(
      err instanceof Error ? err.message : "Error: Failed to create channel",
    );
  }
}

async function handleDeleteChannel(name: string): Promise<void> {
  clearError();
  (getEl("channel-name-input") as HTMLInputElement).value = "";

  if (!state.currentWorkspace) {
    showError("Error: No workspace is open");
    return;
  }

  try {
    await apiDeleteChannel(state.currentWorkspace, name);

    // If the deleted channel was the current one, close it
    if (state.currentChannel === name) {
      hidePostsArea();
    }

    // Refresh channel list
    await loadChannels(state.currentWorkspace);
    renderChannels();
  } catch (err) {
    showError(
      err instanceof Error ? err.message : "Error: Failed to delete channel",
    );
  }
}

async function handleCreatePost(): Promise<void> {
  if (!state.currentWorkspace || !state.currentChannel) return;

  const input = getEl("post-input") as HTMLTextAreaElement;
  const msg = input.value;
  if (!msg.trim()) return;

  try {
    await apiCreatePost(
      state.currentWorkspace,
      state.currentChannel,
      msg,
      state.replyParent,
    );
    input.value = "";
    cancelReply();
  } catch (err) {
    showError(
      err instanceof Error ? err.message : "Error: Failed to create post",
    );
  }
}

function handleReply(postPath: string): void {
  state.replyParent = postPath;
  getEl("reply-info").classList.remove("hidden");
  getEl("reply-label").textContent = "Replying to post...";
  (getEl("post-input") as HTMLTextAreaElement).focus();
}

function cancelReply(): void {
  state.replyParent = "";
  getEl("reply-info").classList.add("hidden");
}

async function handleReact(
  postPath: string,
  reaction: string,
  add: boolean,
): Promise<void> {
  if (!state.username) return;

  try {
    await apiPatchReaction(postPath, reaction, state.username, add);
  } catch (err) {
    slog.error("Failed to update reaction", [
      "error",
      err instanceof Error ? err.message : "unknown",
    ]);
  }
}

// ==================== TOOLBAR HANDLERS ====================

function insertAtCursor(
  textarea: HTMLTextAreaElement,
  before: string,
  after: string,
): void {
  const start = textarea.selectionStart;
  const end = textarea.selectionEnd;
  const text = textarea.value;
  const selected = text.substring(start, end);

  const newText = before + selected + after;
  textarea.value = text.substring(0, start) + newText + text.substring(end);
  textarea.selectionStart = start + before.length;
  textarea.selectionEnd = start + before.length + selected.length;
  textarea.focus();
}

// ==================== INITIALIZATION ====================

function main(): void {
  slog.info("Using database", ["database", `${DB_HOST}${DB_PATH}`]);

  const loginDialog = document.getElementById(
    "login-dialog",
  ) as HTMLDialogElement;
  loginDialog.showModal();

  // Login
  getEl("login-btn").addEventListener("click", handleLogin);
  getEl("username-input").addEventListener("keydown", (e) => {
    if ((e as KeyboardEvent).key === "Enter") {
      handleLogin();
    }
  });

  // Logout
  getEl("logout-btn").addEventListener("click", handleLogout);

  // Workspace buttons
  getEl("open-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleOpenWorkspace(name);
  });

  getEl("create-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleCreateWorkspace(name);
  });

  getEl("delete-workspace-btn").addEventListener("click", () => {
    const input = getEl("workspace-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleDeleteWorkspace(name);
  });

  getEl("refresh-workspaces-btn").addEventListener("click", async () => {
    try {
      await loadWorkspaces();
      renderWorkspaces();
    } catch (err) {
      showError(
        err instanceof Error
          ? err.message
          : "Error: Failed to refresh workspaces",
      );
    }
  });

  // Channel buttons
  getEl("open-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleOpenChannel(name);
  });

  getEl("create-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleCreateChannel(name);
  });

  getEl("delete-channel-btn").addEventListener("click", () => {
    const input = getEl("channel-name-input") as HTMLInputElement;
    const name = input.value.trim();
    if (name) handleDeleteChannel(name);
  });

  getEl("refresh-channels-btn").addEventListener("click", async () => {
    if (!state.currentWorkspace) return;
    try {
      await loadChannels(state.currentWorkspace);
      renderChannels();
    } catch (err) {
      showError(
        err instanceof Error
          ? err.message
          : "Error: Failed to refresh channels",
      );
    }
  });

  // Post buttons
  getEl("post-btn").addEventListener("click", handleCreatePost);
  getEl("cancel-reply-btn").addEventListener("click", cancelReply);

  // Post input - Enter to submit, Shift+Enter for newline
  getEl("post-input").addEventListener("keydown", (e) => {
    const ke = e as KeyboardEvent;
    if (ke.key === "Enter" && !ke.shiftKey) {
      ke.preventDefault();
      handleCreatePost();
    }
  });

  // Error close
  getEl("error-close-btn").addEventListener("click", clearError);

  // Toolbar buttons
  getEl("bold-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "**", "**");
  });

  getEl("italic-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "*", "*");
  });

  getEl("link-btn").addEventListener("click", () => {
    insertAtCursor(getEl("post-input") as HTMLTextAreaElement, "[", "](url)");
  });

  // Emoji insert buttons
  document.querySelectorAll(".emoji-insert-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      const emoji = btn.getAttribute("data-emoji") || "";
      const textarea = getEl("post-input") as HTMLTextAreaElement;
      const start = textarea.selectionStart;
      const text = textarea.value;
      textarea.value =
        text.substring(0, start) + emoji + text.substring(start);
      textarea.selectionStart = start + emoji.length;
      textarea.selectionEnd = start + emoji.length;
      textarea.focus();
    });
  });
}

document.addEventListener("DOMContentLoaded", () => {
  main();
});

